async (params, browser) => {
  // Open Bluesky
  await browser.open('https://bsky.app/')

  // Wait for compose button
  await browser.waitForSelector('[data-testid=\'composePostView\'], button[aria-label*=\'New\'], button[aria-label*=\'compose\'], div[role=\'button\']', 15000)

  await browser.wait(2000)

  // Open compose dialog
  const compose_data = await browser.evaluate(`const composeBtn = document.querySelector('button[aria-label*="New"], button[aria-label*="compose"], button[aria-label*="Write"], div[role="button"][tabindex="0"]'); if (composeBtn) { composeBtn.click(); } return { status: composeBtn ? 'compose_opened' : 'compose_button_not_found', text_to_post: params.text, note: 'The compose dialog has been opened. The text needs to be typed manually or pasted by the user.', url: window.location.href }`)

  return compose_data
}
